sql:
SELECT assignment_id, assignment_priority
FROM test_team_assignments
WHERE assignment_status = 'Active';

external_knowledge:
- "Failed performance tests" refers to tests with a status of 'Failed' and a type of 'Performance';
- "Active standards" refers to standards with a status of 'Active';
- "Minimum passing threshold" refers to the minimum value of all tests with a status of 'Passed'.
